// Parse incoming webhook payload and determine routing
const payload = $input.first().json.body;

if (!payload.action) {
  throw new Error('Missing required field: action');
}

// Route based on action type
const routeMap = {
  'lead_created': { workflow: 'lead-ingestion', type: 'ingestion' },
  'ai_analysis': { workflow: 'ai-lead-analysis', type: 'ai' },
  'send_notification': { workflow: 'send-notification', type: 'notification' },
  'schedule_appointment': { workflow: 'schedule-appointment', type: 'scheduling' },
  'status_update': { workflow: 'webhook-dispatcher', type: 'status' }
};

const route = routeMap[payload.action];
if (!route) {
  console.log('[DISPATCHER] Unknown action:', payload.action, '- passing through');
}

console.log('[DISPATCHER] Routing action:', payload.action, 'to:', route?.workflow || 'passthrough');

return {
  received: true,
  action: payload.action,
  route: route || { workflow: 'unknown', type: 'passthrough' },
  data: payload.data || payload,
  timestamp: new Date().toISOString()
};

// Log the dispatched action
const log = {
  workflow: 'Webhook Dispatcher',
  action: 'dispatch',
  action_type: $json.action,
  route: $json.route?.workflow || 'passthrough',
  status: 'success',
  timestamp: $json.timestamp
};
console.log('[DISPATCHER]', JSON.stringify(log));

return {
  success: true,
  dispatched: true,
  action: $json.action,
  routing: $json.route,
  payload_received: !!$json.received
};

const error = $input.first().json.error || 'Webhook dispatch failed';
console.error('[DISPATCHER ERROR]', error.message || error);
return { success: false, error: error.message || error };
